import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.util.Scanner;

public class XSSSecureCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter your name:");
        String userName = scanner.nextLine();

        System.out.println("Hello, " + userName + "!");

        // Secure code - User input is sanitized before embedding in the HTML response
        String sanitizedUserName = ESAPI.encoder().encodeForHTML(userName);
        System.out.println("<p>Welcome, " + sanitizedUserName + "!</p>");

        scanner.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
